import{_ as a,o as l,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"萬海航運（2615）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2615_萬海.md","filePath":"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2615_萬海.md"}'),i={name:"Deep32Q知識庫/產業洞察/航運產業/02_台灣上市航運股/2615_萬海.md"};function o(n,t,d,s,h,u){return l(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="萬海航運-2615" tabindex="-1">萬海航運（2615） <a class="header-anchor" href="#萬海航運-2615" aria-label="Permalink to &quot;萬海航運（2615）&quot;">​</a></h1><h2 id="📊-基本資料" tabindex="-1">📊 基本資料 <a class="header-anchor" href="#📊-基本資料" aria-label="Permalink to &quot;📊 基本資料&quot;">​</a></h2><ul><li><strong>股票代號</strong>：2615.TW</li><li><strong>定位</strong>：亞洲區間航線主力，近年積極擴張遠洋市場</li><li><strong>特色</strong>：最密集的航班和港口覆蓋率，確保貨運效率與靈活調度</li></ul><h2 id="💰-2025年財務數據" tabindex="-1">💰 2025年財務數據 <a class="header-anchor" href="#💰-2025年財務數據" aria-label="Permalink to &quot;💰 2025年財務數據&quot;">​</a></h2><table tabindex="0"><thead><tr><th>項目</th><th>數值</th><th>同比變化</th></tr></thead><tbody><tr><td>全年合併營收</td><td>新台幣1,403.53億元</td><td>—</td></tr><tr><td>歸屬母公司稅後淨利</td><td>新台幣314.65億元</td><td>—</td></tr><tr><td>EPS</td><td>新台幣11.21元</td><td>史上第四高</td></tr></tbody></table><p><strong>Q4 2025單季表現：</strong></p><ul><li>毛利率：23.92%</li><li>營業利益率：18.94%</li><li>稅前淨利率：28.67%</li><li>稅後淨利率：30.01%</li></ul><blockquote><p>註：受美國關稅議題及區域衝突影響，營收與獲利較前一年下滑，但仍優於市場預期。 來源：CTEE (2026-03-11)</p></blockquote><h2 id="🌏-亞洲航線表現" tabindex="-1">🌏 亞洲航線表現 <a class="header-anchor" href="#🌏-亞洲航線表現" aria-label="Permalink to &quot;🌏 亞洲航線表現&quot;">​</a></h2><ul><li><strong>2025年</strong>：亞洲區間航線運費較去年同期成長超過30%，顯示市場需求強勁</li><li><strong>2026年</strong>：中東衝突導致國際油價波動，萬海已於4月份對亞洲區間航線實施兩波運價調漲（涵蓋東南亞主航線、中日韓航線及港台航線）</li></ul><h2 id="🚢-船隊擴張計畫" tabindex="-1">🚢 船隊擴張計畫 <a class="header-anchor" href="#🚢-船隊擴張計畫" aria-label="Permalink to &quot;🚢 船隊擴張計畫&quot;">​</a></h2><ul><li><strong>2026年</strong>：陸續接收5艘新船</li><li><strong>2027-2030年</strong>：再接收36艘新船</li><li><strong>港口佈局</strong>：高雄港第五貨櫃中心預計2026年底前全面營運；日本大阪港C9貨櫃碼頭（2026年9月起承租營運）</li></ul><h2 id="📈-近期營運重點" tabindex="-1">📈 近期營運重點 <a class="header-anchor" href="#📈-近期營運重點" aria-label="Permalink to &quot;📈 近期營運重點&quot;">​</a></h2><ul><li>持續透過靈活航線配置與船隊管理應對市場波動</li><li>積極更新船隊，導入節能環保設備</li><li>強化港口基礎建設佈局，提升區域競爭力</li></ul><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>CTEE (2026-03-11): 萬海2025全年營收1,403.53億元、EPS 11.21元</li><li>CTEE (2026-05-12): 萬海4月份亞洲區間航線兩波運價調漲</li><li>udn.com: 萬海2025年營運表現分析</li><li>wantgoo.com: 萬季2025 Q4毛利率、營業利益率等財務指標</li></ol>',16)])])}const b=a(i,[["render",o]]);export{_ as __pageData,b as default};
